INSERT INTO procedure_codes (code, description_ar, is_repealed) VALUES
  ('1', 'يتطلب استيرادها وتصديرها موافقة نادي سباقات الخيل', false),
  ('2', 'يتطلب الموافقة المسبقة قبل الاستيراد من وزارة البيئة والمياه والزراعة وتقوم هيئة الزكاة والضريبة والجمارك بعرضها على الحجر النباتي والحيواني لاجازة فسحها من عدمه', false),
  ('3', 'تعرض على المختبرات الخاصة.', false),
  ('4', 'إذا وردت هذه الكائنات حية تعرض على الحجر النباتي والحيواني ( وزارة الزراعة )، وإذا وردت خلاف ذلك تعرض على مختبر مراقبة الجودة والنوعية ( وزارة التجارة والصناعة ). (ملغي)', true),
  ('5', 'تعرض على الحجر الصحي ( وزارة الصحة ) (ملغي)', true),
  ('6', 'إذا كانت صالحة للأكل تعرض على مختبر مراقبة الجودة والنوعية ( وزارة التجارة والاستثمار) وإذا وردت خلاف ذلك ولم تدخل فيها أي عمليات تصنيع تعرض على الحجر النباتي والحيواني ( وزارة الزراعة ). (ملغي)', true),
  ('7', 'للبذار تعرض على الحجر النباتي والحيواني ( وزارة البيئة والمياه والزراعة )، أما اذا كانت صالحة للأكل تعرض الهيئة العامة للغذاء والدواء. (ملغي)', true),
  ('8', 'في حال استيرادها طازجة أو مبردة تعرض على الحجر النباتي والحيواني ( وزارة البيئة والمياه والزراعة ) واذا وردت خلاف ذلك تعرض على الهيئة العامة للغذاء والدواء', false),
  ('9', 'يتطلب استيرادها وتصديرها موافقة الهيئة العامة للامن الغذائي', false),
  ('10', 'يتطلب استيرادها الحصول على ترخيص من هيئة الغذاء والدواء والتأشير على الفواتير بذلك او ابراز شهادة مستقلة. (ملغي)', true),
  ('12', 'تعرض على مختبر الهيئة السعودية للمواصفات والمقاييس والجودة', false),
  ('13', 'يتطلب لاستيرادها وتصديرها موافقة وزارة الداخلية', false),
  ('14', 'تعرض على المختبر المركزي لتحليل الأدوية والأغذية. (ملغي)', true),
  ('15', 'تعرض عند الاستيراد على وزارة الاعلام', false),
  ('16', 'إذا وردت للأغراض الزراعية تعرض على الحجر النباتي والحيواني ( وزارة الزراعة) ، وإذا كانت للأغراض المنزلية تعرض على الهيئة العامة للغذاء والدواء', false),
  ('17', 'تستورد بموجب خطاب من قبل الجهات الحكومية المختصة.', false),
  ('18', 'تعرض على البنك المركزي السعودي', false),
  ('19', 'يشترط أن تكون مصحوبة بشهادة تطهير من الخارج وإلا تعرض على الحجر الصحي. (ملغي)', true),
  ('20', 'الأصناف العسكرية منها تفسح بموجب خطاب رسمي من الجهة العسكرية المستفيدة وفي حال تم استيرادها للشركات والمؤسسات فيتطلب لفسحها موافقة الهيئة العليا للأمن الصناعي بوزارة الداخلية', false),
  ('21', 'يتطلب عند الاستيراد تقديم شهادة مطابقة من نظام سابر (الهيئة السعودية للمواصفات والمقاييس والجودة)', false),
  ('22', 'للأغراض الطبية والعلمية يتطلب موافقة الهيئة العامة للغذاء والدواء , أما للأغراض الخاصة بشركات ومؤسسات الصيانة والخدمات الفنية والمقاولات العامة يتطلب موافقة وزارة التجارة.', false),
  ('23', 'ممنوع استيرادها لغير القطاعات العسكرية (يتطلب لاستيرادها موافقة الجهة العسكرية المستفيدة).', false),
  ('24', 'يتطلب فسح المواد الاولية (الكيميائية) من الجهات الحكومية ذات الاختصاص وذلك حسب نشاط الجهة المستوردة: وزارة الصناعة والثروة المعدنية للمصانع ووزارة التجارة للشركات والمؤسسات ووزارة الطاقة لمواد قطاع البترول ووزارة التعليم للمواد التعليمية ومدينة الملك عبدالعزيز للعلوم والتقنية لمواد الأبحاث والتطوير.', false),
  ('25', 'يتطلب لاستيرادها موافقة هيئة الاتصالات وتقنية المعلومات (ملغى)', false),
  ('26', 'ممنوع استيرادها لغير القطاعات العسكرية , وإذا وردت للجهات الحكومية يتطلب موافقة هذه الجهة', false),
  ('27', 'موافقة الإدارة العامة للآثار بوزارة المعارف للاستيراد والتصدير. (ملغي)', true),
  ('28', 'يتطلب تصدير المواشي ( الأغنام ، الماعز ، الخيل ، الإبل ، البقر ) موافقة من وزارة البيئة والمياه والزراعة.', false),
  ('29', 'يتطلب استيرادها وتصديرها موافقة مسبقة من المركز الوطني لتنمية الحياة الفطرية', false),
  ('31', 'ممنوع تصدير أعلاف الماشية وهي الشعير والذرة البيضاء والسودانية والأعلاف الخضراء والتبن وكذلك اعلاف الدواجن وهي الذرة الصفراء وفول الصويا وفى حالة الاستيراد تتم المصادقة وختم بيانات استيراد هذة الاصناف', false),
  ('32', 'ممنوع تصدير حليب الاطفال بديل الام بكافة أنواعه. (ملغي)', true),
  ('33', 'المشتقات البترولية يتطلب استيرادها أو تصديرها موافقة وزارة الطاقة.', false),
  ('34', 'تصدير الادوية للمصانع الوطنية يتطلب إبراز مايثبت تسجيلها لدى هيئة الغذاء والدواء أو تسجيلها لدى الدولة المستوردة أو إحضار إذن استيراد من الجهات المختصة بالدولة المستوردة، وإعادة تصدير الأدوية يتطلب الحصول على موافقة من هيئة الغذاء والدواء، وخروج الادوية مع الأفراد يتطلب إحضار مستند رسمي من هيئة الغذاء والدواء يسمح لحاملها بإخراجها شريطة أن آلا تحمل شعار هيئة الغذاء والدواء. (ملغي)', true),
  ('35', 'يتطلب تصديرها موافقة وزارة الصناعة والثروة المعدنية.', false),
  ('36', 'حظر تصدير الخضار التالية البطاطس ، البطيخ الحبحب ، البصل الجاف ، الشمام ، القرع اعتبارا من 1433/11/1هـ .(ملغي)', true),
  ('37', 'ممنوع تصدير اسطوانات الغاز الفارغة بمواصفات شركة الغاز والتصنيع الأهلية (غازكو gasco)، واسطوانات الغاز المعبأة بمواصفات شركة الغاز والتصنيع الأهلية (غازكو gasco) يشترط تصديرها إرفاق فاتورة من الشركة. السماح بخروج اسطوانات الغاز الجديدة الفارغة التي يقوم المصنع السعودي لاسطوانات السماح بخروج اسطوانات الغاز الجديدة الفارغة التي يقوم المصنع السعودي لاسطوانات الغاز (انا غاز) بإنتاجها مهما كان نوعها ومواصفاتها.', false),
  ('38', 'يتطلب لتصديرها الحصول على موافقة صندوق التنمية الزراعية (ملغي)', true),
  ('39', 'يتطلب لتصديرها الحصول على موافقة صندوق التنمية الزراعية', false),
  ('40', 'ممنوع استيراد مادة الاسبستوس والسلع والمواد التي تحتوي على هذه المادة.', false),
  ('41', 'ممنوع استيراد مادة برومات البوتاسيوم.', false),
  ('42', 'يمنع تصدير مياه زمزم بموجب الأمر السامي الكريم إلا للحاج والمعتمر بواقع جالون واحد بسعة 5 لتر', false),
  ('44', 'البطاقات الخاصة بأجهزة الاستقبال التلفزيوني يتطلب عرضهاعلى وزارة الثقافة والاعلام (ملغي)', true),
  ('45', 'يتطلب لفسحها موافقة الهيئة العليا للأمن الصناعي بوزارة الداخلية ، وفي حال تم استيرادها من قبل الجهات الحكومية يتم فسحها بموجب خطاب من الجهة المستفيدة', false),
  ('46', 'يتطلب للاستيراد الحصول على ترخيص من هيئة الغذاء والدواء والتأشير على الفواتير بذلك أو ابراز شهادة مستقلة، أما الأدوية البيطرية يتطلب استيرادها موافقة وزارة الزراعة.(ملغي)', true),
  ('47', 'يتطلب استيرادها موافقة الهيئة العامة لتنظيم الإعلام', false),
  ('48', 'المستلزمات الطبية والخيوط الجراحية والحقن الطبية والمستهلكات الطبية والمعدات الطبية إذا كانت مسجلة ضمن نشاط السجل التجاري تفسح مباشرة، وفي حالة عدم إضافتها في السجل التجاري فيتم مراجعة وزارة التجارة والصناعة بحكم الاختصاص. (ملغي)', true),
  ('49', 'السيوف والخناجر والحراب والرماح والاسلحة البيضاء المعدة للزينة تفسح مباشرة، وغير ذلك يتطلب استيرادها الحصول على موافقة من ادارة الاسلحة والمتفجرات بوزارة الداخلية. (ملغي)', true),
  ('50', 'لا تستورد او تصدر هذه المواد الا من قبل جهات حكومية بموجب موافقه مسبقه من وزارة التجارة .', false),
  ('51', 'ممنوع استيراد النفايات الصناعية والمخلفات الخطرة ، نفايات محضرات الصيدلية، مخلفات الصناعات الكيميائية والصناعات المرتبطة بها ، نفايات البلدية ، نفايات المجاري ( وحل ). (ملغي)', true),
  ('52', 'يتطلب استيرادها خطاب فسح من وزارة الداخلية (الهيئة العليا للأمن الصناعي - وحدة التراخيص الامنية) مبني على موافقة مكافحة المخدرات .', false),
  ('53', 'يتطلب استيرادها موافقة من وزارة الصحة (ملغي)', true),
  ('54', 'يتطلب استيرادها وتصديرها موافقة المركز الوطني للرقابة على الالتزام البيئي', false),
  ('55', 'تعفى من الرسوم الجمركية للمستورد وتتحمل الدولة مبالغ هذه الرسوم حتى تاريخ 31/12/2009 م. (ملغي)', true),
  ('56', 'الوسائد الهوائية المحتوية على أي مادة ضمن مواد التي تدخل في تركيب المتفجرات يتطلب استيرادها موافقة الامن الصناعي.', false),
  ('57', 'يلزم الحصول على رخصة تصدير من وزارة التجارة', false),
  ('58', 'يتطلب لاستيرادها الحصول على موافقة هيئة الاتصالات والفضاء والتقنية (ملغي)', true),
  ('59', 'يشترط لإستيرادها و تصديرها الحصول على موافقة مسبقه من وزارة التجارة للشركات والمؤسسات ، وبالنسبة للمصانع من وزارة الصناعه والثروه المعدنية .', false),
  ('60', 'يشترط لفسح أجهزة استقبال القنوات الفضائية رسيفرات والتي تستخدم في فك الشفرات سواء بواسطة شبكة الانترنت أو جهاز صغير مدمج مع جهاز الرسيفر ، أن يكون لدى مستورد هذه الاجهزة مايلي: (ملغي) 1ـ ترخيص من وزارة الثقافة والاعلام بمزاولة النشاط. 2ـ أن ينص على هذا النشاط في السجل التجاري. بحيث يتم ادخال رقم الترخيص ورقم السجل التجاري المتضمن هذا النشاط للبنود الجمركية الخاصة بهذه الاجهزة لفسحها ، وفي حالة عدم تقديم ذلك تحجز الارسالية ويطلب من المستورد مراجعة وزارة الثقافة والاعلام للاعلام الداخل.', false),
  ('61', 'تعرض عند الاستيراد على الهيئة العامة للغذاء والدواء للموافقة على الفسح من عدمه', false),
  ('62', 'فسح مستوردات الهيئات الدبلوماسية والقنصلية والمنظمات الدولية يستلزم تقديم نموذج فسح من وزارة الخارجية معتمدا من ديوان المصلحة.(ملغي)', true),
  ('63', 'يشترط الحصول على موافقة وزارة الداخلية - إدارة الاسلحة والمتفجرات - عند الاستيراد والتصدير', false),
  ('64', 'نادي الطيران السعودي (ملغي)', true),
  ('65', 'يتطلب استيرادها وتصديرها موافقة مسبقة من المركز الوطني لتنمية الحياة الفطرية (ملغي)', true),
  ('66', 'يمنع تصدير مياه الشرب المعبأه والثلج إلى خارج المملكة بما في ذلك مياه زمزم (ملغي)', true),
  ('67', 'يلزم خطاب للاستيراد والتصدير من وزارة البترول والثروة المعدينة.(ملغي)', true),
  ('68', 'يتطلب لاستيرادها موافقة الهيئة العليا للامن الصناعي وحده التراخيص الامنية للمواد التي تدخل في تركيب المتفجرات.', false),
  ('69', 'مايرد لشركة الزيت العربية السعودية (ارامكو السعودية) (ملغي)', true),
  ('70', 'منع استيراد الفحم من الصومال على نحو مباشر أو غير مباشر تنفيذا لقرار مجلس الامن 2036 (2012) (ملغي)', true),
  ('71', 'يتطلب تصديرها تحصيل مبلغ الاعانه وقيمته 2000 ريال عن كل طن (ملغي)', true),
  ('72', 'يتطلب تصديرها اجراء تحليل للتأكد من مطابقة المادة المصدرة مع التحليل', false),
  ('74', 'فسح الاجهزة الضوئية والصوتية (سفتي واشارات انذار ضوئي) بخطاب من وزارة الداخلية - المرور', false),
  ('75', 'يتطلب تصديرها عرضها على ديوان هيئة الزكاة والضريبة والجمارك (الادارة العامة للتعرفة).', false),
  ('76', 'يمنع دخول تبغ المضغ', false),
  ('77', 'يمنع دخول القرآن الكريم بأي شكل كان بما في ذلك المصاحف الإلكترونية والاقلام القارئة للقرآن الكريم (للكميات التجارية).', false),
  ('78', 'منع دخول الطيور الحية من جميع دول العالم ماعدا بيض التفقيس والصيصان الخاضعة للرقابة الفنية الواردة في تعميم ديوان المصلحة رقم 43/512/م وتاريخ 1426/10/11هـ المبني على الامر السامي البرقي رقم 11261/م ب وتاريخ (ملغي)1426/10/10هـ. باستثناء الصقور الواردة التي استثنيت بالامر السامي رقم 12690/م ب وتاريخ 1426/12/2هـ ورقم 3150/م ب وتاريخ 1428/3/26هـ القاضية بالموافقة على السماح بدخول صقور الصيد للمملكة من خلال المنافذ التي تم تحديدها عن طريق ( مطار الملك خالد الدولي ، الحديثة ، الرقعي ، جسر الملك فهد ، سلوى ، البطحاء).', false),
  ('79', 'منع ثمار الفورو بكمية تجارية ويستثنى ما يرد مع الحجاج بما لايزيد عن 2كيلوجرام (تم الايقاف)', false),
  ('80', 'ارفاق شهادة مطابقة تتضمن إختبار كفاءة إستهلاك الطاقة ، وبطاقة كفاءة إستهلاك الطاقة. أو عرض على هيئة السعودية للمواصفات والمقاييس والجودة.', false),
  ('81', 'يتطلب موافقة هيئة الزكاة والضريبة والجمارك (الإدارة العامة للتعرفة) ولا يتطلب استحصال فرق السعر العالمي عند التصدير', false),
  ('82', 'استيراد القار النفطي (الاسفلت)يتطلب موافقة وزارة البترول والثروة المعدنية . (ملغي)', true),
  ('84', 'ممنوع استيرادها (ملغي)', true),
  ('85', 'ممنوع تصديرها الا بتصريح من امارة المنطقة بالمشاركة في المهرجانات والمسابقات والمزينات التي تقام في دول مجلس التعاون لدول الخليج العربية على ان تستكمل الاشتراطات المبلغه في خطاب ديوان المصلحة رقم 43/780/م وتاريخ 1436/11/22هـ (ملغي)', true),
  ('86', 'المطبوعات التي تحمل شعار جهة حكومية تفسح بخطاب من الجهة ذات العلاقة. اما المطبوعات الامنية يتم فسحها بموجب خطاب من مصلحة المطابع الحكومية.', false),
  ('87', 'يلزم موافقة الهيئة العامة للغذاء والدواء (للسلائف الكيميائية عند الاستيراد)', false),
  ('88', 'يتطلب تصديرها خطاب مرفق موافقة وزارة الزراعة على ذبحها وأن يدون على غلاف منتجها النهائي عبارة دجاج بياض بخط واضح غير قابل للازالة (ملغي)', true),
  ('89', 'ارفاق شهادة مطابقة مدون بها رقم التسجيل لدى الهيئة السعودية للمواصفات والمقاييس والجودة وبطاقة كفاءة استهلاك الطاقة أو عرض على هيئة السعودية للمواصفات والمقاييس والجودة.', false),
  ('90', 'قيادة طيران الأمن (ملغي)', true),
  ('91', 'يشترط لفسحها عند الاستيراد الحصول على موافقة الهيئة العامة للطيران المدني', false),
  ('92', 'يتطلب الحصول على رخصة تصدير من وزارة البيئة والمياه والزراعة', false),
  ('93', 'يشترط الحصول على إذن تصدير من وزارة البيئة والمياه والزراعة', false),
  ('94', 'يتطلب الحصول على تصريح من الإتحاد السعودي للهجن عند التصدير', false),
  ('95', 'يتطلب الحصول على تصريح من نادي الإبل عند التصدير', false),
  ('96', 'يلزم العرض على الإدارة العامة للقيود والتعريفة الجمركية بديوان الهيئة', false),
  ('97', 'يلزم موافقة المديرية العامة لمكافحة المخدرات (للسلائف الكيميائية عند التصدير)', false),
  ('98', 'يتطلب لتصديرها الحصول على موافقة من الهيئة العامة للغذاء والدواء', false),
